void BEVFusionNode::cloudCallback(
  const std::shared_ptr<const cuda_blackboard::CudaPointCloud2> & pc_msg_ptr)
{
  const auto objects_sub_count =
    objects_pub_->get_subscription_count() + objects_pub_->get_intra_process_subscription_count();

  lidar_frame_ = pc_msg_ptr->header.frame_id;
  if (objects_sub_count < 1 || !checkSensorFusionReadiness()) {
    return;
  }

  if (stop_watch_ptr_) {
    stop_watch_ptr_->toc("processing/total", true);
  }

  precomputeIntrinsicsExtrinsics();

  diagnostics_detector_trt_->clear();

  const double lidar_stamp = rclcpp::Time(pc_msg_ptr->header.stamp).seconds();
  computeCameraMasks(lidar_stamp);

  std::vector<Box3D> det_boxes3d;
  std::unordered_map<std::string, double> proc_timing;
  bool is_num_voxels_within_range = true;
  const bool is_success = detector_ptr_->detect(
    pc_msg_ptr, camera_data_ptrs_, camera_masks_, tf_buffer_, det_boxes3d, proc_timing,
    is_num_voxels_within_range);

  if (!is_success) {
    RCLCPP_ERROR_THROTTLE(
      this->get_logger(), *this->get_clock(), 1000,
      "BEVFusion detection failed. No detection results will be published.");
    return;
  }

  diagnostics_detector_trt_->add_key_value(
    "is_num_voxels_within_range", is_num_voxels_within_range);
  if (!is_num_voxels_within_range) {
    std::stringstream message;
    message << "BEVFusionTRT::detect: The actual number of voxels exceeds its maximum value, "
            << "which may limit the detection performance.";
    diagnostics_detector_trt_->update_level_and_message(
      diagnostic_msgs::msg::DiagnosticStatus::WARN, message.str());
  }

  std::vector<autoware_perception_msgs::msg::DetectedObject> raw_objects;
  raw_objects.reserve(det_boxes3d.size());
  for (const auto & box3d : det_boxes3d) {
    autoware_perception_msgs::msg::DetectedObject obj;
    box3DToDetectedObject(box3d, class_names_, obj);
    raw_objects.emplace_back(obj);
  }

  autoware_perception_msgs::msg::DetectedObjects output_msg;
  output_msg.header = pc_msg_ptr->header;
  output_msg.objects = iou_bev_nms_.apply(raw_objects);

  detection_class_remapper_.mapClasses(output_msg);

  publishDetectionResults(output_msg, pc_msg_ptr->header);
  publishDebugInfo(proc_timing, output_msg.header);
}

bool BEVFusionNode::checkSensorFusionReadiness()
{
  if (!sensor_fusion_) {
    return true;
  }

  if (!areAllSensorDataAvailable()) {
    RCLCPP_WARN_THROTTLE(
      this->get_logger(), *this->get_clock(), 5000,
      "Sensor fusion mode enabled but missing required data: extrinsics_available=%s, "
      "images_available=%s, intrinsics_available=%s. Skipping detection",
      extrinsics_available_ ? "true" : "false", images_available_ ? "true" : "false",
      intrinsics_available_ ? "true" : "false");
    return false;
  }

  return true;
}

bool BEVFusionNode::areAllSensorDataAvailable() const
{
  return extrinsics_available_ && images_available_ && intrinsics_available_;
}

void BEVFusionNode::precomputeIntrinsicsExtrinsics()
{
  if (!sensor_fusion_ || intrinsics_extrinsics_precomputed_) {
    return;
  }

  std::vector<sensor_msgs::msg::CameraInfo> camera_info_msgs;
  std::vector<Matrix4f> lidar2camera_extrinsics;

  try {
    std::transform(
      camera_data_ptrs_.begin(), camera_data_ptrs_.end(), std::back_inserter(camera_info_msgs),
      [](const auto & camera_data) { return camera_data->camera_info_value(); });
  } catch (const std::runtime_error & e) {
    RCLCPP_WARN_STREAM(
      rclcpp::get_logger("bevfusion"), "Camera info is not available for some cameras!");
    return;
  }

  std::transform(
    lidar2camera_extrinsics_.begin(), lidar2camera_extrinsics_.end(),
    std::back_inserter(lidar2camera_extrinsics), [](const auto & opt) { return *opt; });

  detector_ptr_->setIntrinsicsExtrinsics(camera_info_msgs, lidar2camera_extrinsics);
  intrinsics_extrinsics_precomputed_ = true;
}

void BEVFusionTRT::setIntrinsicsExtrinsics(
  std::vector<sensor_msgs::msg::CameraInfo> & camera_info_vector,
  std::vector<Matrix4fRowM> & lidar2camera_vector)
{
  roi_start_y_vector_.clear();
  img_aug_matrices_.clear();

  for (std::int64_t i = 0; i < config_.num_cameras_; i++) {
    int crop_h = static_cast<int>(config_.resized_height_ - config_.roi_height_);
    int crop_w =
      std::max(0, static_cast<int>(config_.resized_width_) - static_cast<int>(config_.roi_width_)) /
      2;

    Matrix4fRowM img_aug_matrix = Matrix4fRowM::Identity();
    img_aug_matrix(0, 0) = config_.img_aug_scale_x_;
    img_aug_matrix(1, 1) = config_.img_aug_scale_y_;
    img_aug_matrix(0, 3) = -static_cast<float>(crop_w);
    img_aug_matrix(1, 3) = -static_cast<float>(crop_h);

    img_aug_matrices_.push_back(img_aug_matrix);
    roi_start_y_vector_.push_back(crop_h);
  }

  auto [lidar2images_flattened, geom_feats, kept, ranks, indices] =
    precomputeFeatures(lidar2camera_vector, img_aug_matrices_, camera_info_vector, config_);

  assert(
    static_cast<std::int64_t>(lidar2images_flattened.size()) ==
    config_.num_cameras_ * BEVFusionConfig::kTransformMatrixDim *
      BEVFusionConfig::kTransformMatrixDim);

  assert(
    static_cast<std::int64_t>(geom_feats.size()) <=
    config_.num_cameras_ * BEVFusionConfig::kTransformMatrixDim * config_.features_height_ *
      config_.features_width_ * config_.num_depth_features_);
  assert(
    static_cast<std::int64_t>(kept.size()) == config_.num_cameras_ * config_.features_height_ *
                                                config_.features_width_ *
                                                config_.num_depth_features_);
  assert(
    static_cast<std::int64_t>(ranks.size()) <= config_.num_cameras_ * config_.features_height_ *
                                                 config_.features_width_ *
                                                 config_.num_depth_features_);
  assert(
    static_cast<std::int64_t>(indices.size()) <= config_.num_cameras_ * config_.features_height_ *
                                                   config_.features_width_ *
                                                   config_.num_depth_features_);

  num_geom_feats_ = static_cast<std::int64_t>(geom_feats.size());
  num_kept_ = static_cast<std::int64_t>(kept.size());
  num_ranks_ = static_cast<std::int64_t>(ranks.size());
  num_indices_ = static_cast<std::int64_t>(indices.size());

  assert(num_geom_feats_ == BEVFusionConfig::kTransformMatrixDim * num_ranks_);
  assert(num_ranks_ == num_indices_);

  CHECK_CUDA_ERROR(cudaMemcpy(
    lidar2image_d_.get(), lidar2images_flattened.data(),
    config_.num_cameras_ * BEVFusionConfig::kTransformMatrixDim *
      BEVFusionConfig::kTransformMatrixDim * sizeof(float),
    cudaMemcpyHostToDevice));
  CHECK_CUDA_ERROR(cudaMemcpy(
    geom_feats_d_.get(), geom_feats.data(), num_geom_feats_ * sizeof(std::int32_t),
    cudaMemcpyHostToDevice));
  CHECK_CUDA_ERROR(cudaMemcpy(
    kept_d_.get(), kept.data(), num_kept_ * sizeof(std::uint8_t), cudaMemcpyHostToDevice));
  CHECK_CUDA_ERROR(cudaMemcpy(
    ranks_d_.get(), ranks.data(), num_ranks_ * sizeof(std::int64_t), cudaMemcpyHostToDevice));
  CHECK_CUDA_ERROR(cudaMemcpy(
    indices_d_.get(), indices.data(), num_indices_ * sizeof(std::int64_t), cudaMemcpyHostToDevice));

  // Copy img_aug_matrix data for fusion model (fusion model always uses separate image backbone)
  // Each Matrix4fRowM is contiguous, copy each matrix directly to its position in device memory
  if (config_.sensor_fusion_) {
    const std::size_t matrix_size =
      BEVFusionConfig::kTransformMatrixDim * BEVFusionConfig::kTransformMatrixDim;

    for (std::int64_t i = 0; i < config_.num_cameras_; i++) {
      CHECK_CUDA_ERROR(cudaMemcpy(
        img_aug_matrix_d_.get() + i * matrix_size, img_aug_matrices_[i].data(),
        matrix_size * sizeof(float), cudaMemcpyHostToDevice));
    }
  }
}

precomputeFeatures(
  const std::vector<Matrix4fRowM> & lidar2camera_transforms,
  const std::vector<Matrix4fRowM> & camera_aug_matrices,
  const std::vector<sensor_msgs::msg::CameraInfo> & camera_info_vector,
  const BEVFusionConfig & config)
{
  Eigen::VectorXf lidar2images_flat(config.num_cameras_ * 4 * 4);

  Tensor4D frustum = autoware::bevfusion::createFrustum(config);

  Tensor3D camera2lidar_rotations(config.num_cameras_, 3, 3);
  Tensor2D camera2lidar_translations(config.num_cameras_, 3);
  Tensor3D intrinsics_inverse(config.num_cameras_, 3, 3);
  Tensor3D post_rots_inverse(config.num_cameras_, 3, 3);
  Tensor2D post_trans(config.num_cameras_, 3);

  for (std::int64_t camera_id = 0; camera_id < config.num_cameras_; camera_id++) {
    Matrix4fRowM cam2image = Matrix4fRowM::Identity();
    cam2image(0, 0) = camera_info_vector[camera_id].p[0];
    cam2image(1, 1) = camera_info_vector[camera_id].p[5];
    cam2image(0, 2) = camera_info_vector[camera_id].p[2];
    cam2image(1, 2) = camera_info_vector[camera_id].p[6];

    Matrix4fRowM img_aug_matrix = camera_aug_matrices[camera_id];
    Matrix4fRowM img_aug_matrix_inverse = img_aug_matrix.inverse().eval();

    Matrix4fRowM lidar2camera = lidar2camera_transforms[camera_id];
    Matrix4fRowM camera2lidar = lidar2camera.inverse().eval();

    Matrix4fRowM lidar2image = cam2image * lidar2camera;
    Eigen::VectorXf lidar2image_flat(Eigen::Map<Eigen::VectorXf>(lidar2image.data(), 16));
    lidar2images_flat.segment(16 * camera_id, 16) = lidar2image_flat;

    Matrix3fRowM camera2lidar_rot = camera2lidar.block<3, 3>(0, 0);
    Vector3fRowM camera2lidar_trans = camera2lidar.block<3, 1>(0, 3);
    Matrix3fRowM intrinsics_inverse_matrix = cam2image.inverse().eval().block<3, 3>(0, 0);
    Matrix3fRowM post_rots_inv = img_aug_matrix_inverse.block<3, 3>(0, 0);
    Vector3fRowM post_trans_vec = img_aug_matrix.block<3, 1>(0, 3);

    TensorMap2D camera2lidar_rot_tensor(camera2lidar_rot.data(), 3, 3);
    TensorMap1D camera2lidar_trans_tensor(camera2lidar_trans.data(), 3);
    TensorMap2D intrinsics_inverse_tensor(intrinsics_inverse_matrix.data(), 3, 3);
    TensorMap2D post_rots_inv_tensor(post_rots_inv.data(), 3, 3);
    TensorMap1D post_trans_tensor(post_trans_vec.data(), 3);

    camera2lidar_rotations.chip(camera_id, 0) = camera2lidar_rot_tensor;
    camera2lidar_translations.chip(camera_id, 0) = camera2lidar_trans_tensor;
    intrinsics_inverse.chip(camera_id, 0) = intrinsics_inverse_tensor;
    post_rots_inverse.chip(camera_id, 0) = post_rots_inv_tensor;
    post_trans.chip(camera_id, 0) = post_trans_tensor;
  }

  Tensor5D geometry = getGeometry(
    frustum,                    // [D, H, W, 3]
    camera2lidar_rotations,     // [N, 3, 3]
    camera2lidar_translations,  // [N, 3]
    intrinsics_inverse,         // [N, 3, 3]
    post_rots_inverse,          // [N, 3, 3]
    post_trans                  // [N, 3]
  );

  auto [geom_feats, kept, ranks, indices] = bevPoolAux(geometry, config);

  return std::make_tuple(lidar2images_flat, geom_feats, kept, ranks, indices);
}

Tensor4D createFrustum(const BEVFusionConfig & config)
{
  const float dbound_start = config.d_bound_[0];
  const float dbound_end = config.d_bound_[1];
  const float dbound_step = config.d_bound_[2];
  const int roi_height = static_cast<int>(config.roi_height_);            // Image height
  const int roi_width = static_cast<int>(config.roi_width_);              // Image width
  const int features_height = static_cast<int>(config.features_height_);  // Feature height
  const int features_width = static_cast<int>(config.features_width_);    // Feature width

  // Compute D (number of depth layers)
  int D = static_cast<Eigen::Index>(std::floor((dbound_end - dbound_start) / dbound_step));
  assert(static_cast<std::int64_t>(D) == config.num_depth_features_);

  Tensor1D ds_vec(D);
  for (Eigen::Index i = 0; i < D; ++i) {
    ds_vec(i) = dbound_start + i * dbound_step;
  }

  // Create xs_lin and ys_lin tensors
  Tensor1D xs_lin(features_width);
  for (Eigen::Index i = 0; i < features_width; ++i) {
    xs_lin(i) = static_cast<double>(i) * (roi_width - 1) / (features_width - 1);
  }

  Tensor1D ys_lin(features_height);
  for (Eigen::Index i = 0; i < features_height; ++i) {
    ys_lin(i) = static_cast<double>(i) * (roi_height - 1) / (features_height - 1);
  }

  // Reshape and broadcast ds_vec to (D, features_height, features_width)
  Tensor3D ds_tensor = ds_vec.reshape(Eigen::array<Eigen::Index, 3>{D, 1, 1});
  Tensor3D ds_broadcast =
    ds_tensor.broadcast(Eigen::array<Eigen::Index, 3>{1, features_height, features_width});

  // Reshape and broadcast xs_lin to (1, 1, features_width)
  Tensor3D xs_tensor = xs_lin.reshape(Eigen::array<Eigen::Index, 3>{1, 1, features_width});
  Tensor3D xs_broadcast = xs_tensor.broadcast(Eigen::array<Eigen::Index, 3>{D, features_height, 1});

  // Reshape and broadcast ys_lin to (1, features_height, 1)
  Tensor3D ys_tensor = ys_lin.reshape(Eigen::array<Eigen::Index, 3>{1, features_height, 1});
  Tensor3D ys_broadcast = ys_tensor.broadcast(Eigen::array<Eigen::Index, 3>{D, 1, features_width});

  // Stack xs, ys, ds along the last dimension to form frustum
  Tensor4D frustum(D, features_height, features_width, 3);
  frustum.chip(0, 3) = xs_broadcast;
  frustum.chip(1, 3) = ys_broadcast;
  frustum.chip(2, 3) = ds_broadcast;

  return frustum;
}

Tensor5D getGeometry(
  const Tensor4D & frustum,             // [D, H, W, 3]
  const Tensor3D & camera2lidar_rots,   // [N, 3, 3]
  const Tensor2D & camera2lidar_trans,  // [N, 3]
  const Tensor3D & intrinsics_inverse,  // [N, 3, 3]
  const Tensor3D & post_rots_inverse,   // [N, 3, 3]
  const Tensor2D & post_trans           // [N, 3]
)
{
  // Get dimensions
  int N = camera2lidar_trans.dimension(0);
  int D = frustum.dimension(0);
  int H = frustum.dimension(1);
  int W = frustum.dimension(2);

  // Reshape and broadcast frustum to [N, D, H, W, 3]
  Tensor5D frustum_broadcast = frustum.reshape(Eigen::array<Eigen::Index, 5>{1, D, H, W, 3})
                                 .broadcast(Eigen::array<Eigen::Index, 5>{N, 1, 1, 1, 1});

  // Reshape post_trans to [N, 1, 1, 1, 3]
  Tensor5D post_trans_broadcast = post_trans.reshape(Eigen::array<Eigen::Index, 5>{N, 1, 1, 1, 3})
                                    .broadcast(Eigen::array<Eigen::Index, 5>{1, D, H, W, 1});

  // Subtract post_trans from frustum
  Tensor5D points = frustum_broadcast - post_trans_broadcast;

  // cSpell:ignore unsqueezed
  // Unsqueeze points to [N, D, H, W, 3, 1]
  Tensor6D points_unsqueezed = points.reshape(Eigen::array<Eigen::Index, 6>{N, D, H, W, 3, 1});

  Tensor5D points_rotated(N, D, H, W, 3);

  for (Eigen::Index camera_index = 0; camera_index < N; camera_index++) {
    Tensor2D post_rot_inverse = post_rots_inverse.chip(camera_index, 0);
    Tensor4D points_sliced = points.chip(camera_index, 0);

    Eigen::array<Eigen::IndexPair<int>, 1> contract_dims = {Eigen::IndexPair<int>(3, 0)};
    Eigen::array<int, 2> shuffling({1, 0});
    Tensor2D post_rot_inverse_transposed = post_rot_inverse.shuffle(shuffling);

    Tensor4D points_sliced_rotated =
      points_sliced.contract(post_rot_inverse_transposed, contract_dims);
    points_rotated.chip(camera_index, 0) = points_sliced_rotated;
  }

  // Remove the last dimension (size 1)
  Tensor5D points_squeezed = points_rotated;

  Tensor5D points_xy = points_squeezed.slice(
    Eigen::array<Eigen::Index, 5>{0, 0, 0, 0, 0}, Eigen::array<Eigen::Index, 5>{N, D, H, W, 2});
  Tensor5D points_z = points_squeezed.slice(
    Eigen::array<Eigen::Index, 5>{0, 0, 0, 0, 2}, Eigen::array<Eigen::Index, 5>{N, D, H, W, 1});
  Tensor5D points_xy_scaled =
    points_xy * points_z.broadcast(Eigen::array<Eigen::Index, 5>{1, 1, 1, 1, 2});

  // Concatenate points_xy_scaled and points_z along the last dimension
  Tensor5D points_cat(points_squeezed.dimensions());
  points_cat.slice(
    Eigen::array<Eigen::Index, 5>{0, 0, 0, 0, 0}, Eigen::array<Eigen::Index, 5>{N, D, H, W, 2}) =
    points_xy_scaled;
  points_cat.slice(
    Eigen::array<Eigen::Index, 5>{0, 0, 0, 0, 2}, Eigen::array<Eigen::Index, 5>{N, D, H, W, 1}) =
    points_z;

  Tensor3D combine(intrinsics_inverse.dimensions());

  for (Eigen::Index camera_index = 0; camera_index < N; camera_index++) {
    Tensor2D camera2lidar_rot = camera2lidar_rots.chip(camera_index, 0);
    Tensor2D intrinsics_inverse_aux = intrinsics_inverse.chip(camera_index, 0);

    Eigen::array<Eigen::IndexPair<int>, 1> contract_dims = {Eigen::IndexPair<int>(1, 0)};

    Tensor2D combine_sliced = camera2lidar_rot.contract(intrinsics_inverse_aux, contract_dims);
    combine.chip(camera_index, 0) = combine_sliced;
  }

  // Reshape combine to [N, 1, 1, 1, 3, 3]
  Tensor6D combine_reshaped = combine.reshape(Eigen::array<Eigen::Index, 6>{N, 1, 1, 1, 3, 3});

  Tensor5D points_transformed(points_cat.dimensions());

  for (Eigen::Index camera_index = 0; camera_index < N; camera_index++) {
    Tensor2D combine_sliced = combine.chip(camera_index, 0);
    Tensor4D points_sliced = points_cat.chip(camera_index, 0);

    Eigen::array<Eigen::IndexPair<int>, 1> contract_dims = {Eigen::IndexPair<int>(3, 0)};
    Eigen::array<int, 2> shuffling({1, 0});
    Tensor2D combined_transposed = combine_sliced.shuffle(shuffling);

    Tensor4D points_transformed_sliced = points_sliced.contract(combined_transposed, contract_dims);
    points_transformed.chip(camera_index, 0) = points_transformed_sliced;
  }

  // Squeeze the last dimension
  Tensor5D points_squeezed_final =
    points_transformed.reshape(Eigen::array<Eigen::Index, 5>{N, D, H, W, 3});

  // Add camera2lidar_trans
  Tensor5D camera2lidar_trans_broadcast =
    camera2lidar_trans.reshape(Eigen::array<Eigen::Index, 5>{N, 1, 1, 1, 3})
      .broadcast(Eigen::array<Eigen::Index, 5>{1, D, H, W, 1});
  Tensor5D points_final = points_squeezed_final + camera2lidar_trans_broadcast;

  return points_final;
}

class TensorBase<Derived, ReadOnlyAccessors>
{
  public:
    typedef internal::traits<Derived> DerivedTraits;
    typedef typename DerivedTraits::Scalar Scalar;
    typedef typename DerivedTraits::Index Index;
    typedef typename internal::remove_const<Scalar>::type CoeffReturnType;
    static const int NumDimensions = DerivedTraits::NumDimensions;

    // Generic nullary operation support.
    template <typename CustomNullaryOp> EIGEN_DEVICE_FUNC
    EIGEN_STRONG_INLINE const TensorCwiseNullaryOp<CustomNullaryOp, const Derived>
    nullaryExpr(const CustomNullaryOp& func) const {
      return TensorCwiseNullaryOp<CustomNullaryOp, const Derived>(derived(), func);
    }

    // Coefficient-wise nullary operators
    EIGEN_DEVICE_FUNC
    EIGEN_STRONG_INLINE const TensorCwiseNullaryOp<internal::scalar_constant_op<Scalar>, const Derived>
    constant(const Scalar& value) const {
      return nullaryExpr(internal::scalar_constant_op<Scalar>(value));
    }

    EIGEN_DEVICE_FUNC
    EIGEN_STRONG_INLINE const TensorCwiseNullaryOp<internal::UniformRandomGenerator<Scalar>, const Derived>
    random() const {
      return nullaryExpr(internal::UniformRandomGenerator<Scalar>());
    }
    template <typename RandomGenerator> EIGEN_DEVICE_FUNC
    EIGEN_STRONG_INLINE const TensorCwiseNullaryOp<RandomGenerator, const Derived>

> bevPoolAux(
    const Tensor5D& geom_feats_input,
    const BEVFusionConfig & config)
{
  Eigen::Vector3f dx(config.x_bound_[2], config.y_bound_[2], config.z_bound_[2]);
  Eigen::Vector3f bx(
    config.x_bound_[0] + config.x_bound_[2] / 2.0, config.y_bound_[0] + config.y_bound_[2] / 2.0,
    config.z_bound_[0] + config.z_bound_[2] / 2.0);
  Eigen::Vector3i nx(
    static_cast<int>((config.x_bound_[1] - config.x_bound_[0]) / config.x_bound_[2]),
    static_cast<int>((config.y_bound_[1] - config.y_bound_[0]) / config.y_bound_[2]),
    static_cast<int>((config.z_bound_[1] - config.z_bound_[0]) / config.z_bound_[2]));

  // Get dimensions
  Eigen::Index N = geom_feats_input.dimension(0);
  Eigen::Index D = geom_feats_input.dimension(1);
  Eigen::Index H = geom_feats_input.dimension(2);
  Eigen::Index W = geom_feats_input.dimension(3);
  Eigen::Index C = geom_feats_input.dimension(4);
  assert(C == 3);

  Eigen::Index Nprime = N * D * H * W;

  TensorMap1D dx_map(dx.data(), 3);
  TensorMap1D bx_map(bx.data(), 3);

  Tensor5D dx_broadcast = dx_map.reshape(Eigen::array<Eigen::Index, 5>{1, 1, 1, 1, C})
                            .broadcast(Eigen::array<Eigen::Index, 5>{N, D, H, W, 1});

  Tensor5D bx_broadcast = bx_map.reshape(Eigen::array<Eigen::Index, 5>{1, 1, 1, 1, 3})
                            .broadcast(Eigen::array<Eigen::Index, 5>{N, D, H, W, 1});

  Tensor5D geom_feats_aux = (geom_feats_input - (bx_broadcast - 0.5 * dx_broadcast)) / dx_broadcast;

  Eigen::Map<const Eigen::Matrix<float, Eigen::Dynamic, 3, Eigen::RowMajor>> geom_feats_map(
    geom_feats_aux.data(), Nprime, C);
  Eigen::Matrix<std::int32_t, Eigen::Dynamic, 3, Eigen::RowMajor> geom_feats_int =
    geom_feats_map.cast<std::int32_t>();

  // Concatenate geom_feats_int and batch_ix along column
  Eigen::Matrix<std::int32_t, Eigen::Dynamic, 4, Eigen::RowMajor> geom_feats_cat(Nprime, 4);
  geom_feats_cat.block(0, 0, Nprime, C) = geom_feats_int;
  geom_feats_cat.col(3).setZero();

  // Filter out points outside box
  Eigen::Matrix<std::uint8_t, 1, Eigen::Dynamic, Eigen::RowMajor> kept(Nprime);
  for (Eigen::Index i = 0; i < Nprime; ++i) {
    int32_t x = geom_feats_cat(i, 0);
    int32_t y = geom_feats_cat(i, 1);
    int32_t z = geom_feats_cat(i, 2);

    bool keep = (x >= 0) && (x < nx(0)) && (y >= 0) && (y < nx(1)) && (z >= 0) && (z < nx(2));
    kept(i) = keep;
  }

  // Collect indices where kept is true
  std::vector<std::int64_t> kept_indices;
  for (Eigen::Index i = 0; i < Nprime; ++i) {
    if (kept(i)) {
      kept_indices.push_back(i);
    }
  }

  // Create geom_feats_kept
  Eigen::Index N_kept = kept_indices.size();
  Eigen::Matrix<std::int32_t, Eigen::Dynamic, 4, Eigen::RowMajor> geom_feats_kept(N_kept, 4);
  for (Eigen::Index i = 0; i < N_kept; ++i) {
    std::int64_t idx = kept_indices[i];
    geom_feats_kept.row(i) = geom_feats_cat.row(idx);
  }

  // Compute ranks
  Eigen::Matrix<std::int64_t, 1, Eigen::Dynamic, Eigen::RowMajor> ranks(N_kept);
  std::int64_t factor0 = static_cast<std::int64_t>(nx(1)) * nx(2);
  std::int64_t factor1 = static_cast<std::int64_t>(nx(2));
  std::int64_t factor2 = 1;

  for (Eigen::Index i = 0; i < N_kept; ++i) {
    std::int32_t x = geom_feats_kept(i, 0);
    std::int32_t y = geom_feats_kept(i, 1);
    std::int32_t z = geom_feats_kept(i, 2);
    std::int64_t batch = geom_feats_kept(i, 3);

    std::int64_t rank = x * factor0 + y * factor1 + z * factor2 + batch;
    ranks(i) = rank;
  }

  //  Sort ranks and get indices
  std::vector<std::pair<std::int64_t, std::int64_t>> rank_idx_pairs(N_kept);
  for (Eigen::Index i = 0; i < N_kept; ++i) {
    rank_idx_pairs[i] = std::make_pair(ranks(i), i);
  }
  std::sort(rank_idx_pairs.begin(), rank_idx_pairs.end());

  //  Create sorted ranks and indices
  Eigen::Matrix<std::int64_t, 1, Eigen::Dynamic, Eigen::RowMajor> ranks_sorted(N_kept);
  Eigen::Matrix<std::int64_t, 1, Eigen::Dynamic, Eigen::RowMajor> indices(N_kept);
  Eigen::Matrix<std::int32_t, Eigen::Dynamic, 4, Eigen::RowMajor> geom_feats_sorted(N_kept, 4);
  for (Eigen::Index i = 0; i < N_kept; ++i) {
    std::int64_t rank = rank_idx_pairs[i].first;
    std::int64_t idx = rank_idx_pairs[i].second;

    ranks_sorted(i) = rank;
    indices(i) = idx;
    geom_feats_sorted.row(i) = geom_feats_kept.row(idx);
  }

  //  Return geom_feats_sorted, kept, ranks_sorted, indices
  return std::make_tuple(geom_feats_sorted, kept, ranks_sorted, indices);
}

void BEVFusionNode::computeCameraMasks(double lidar_stamp)
{
  camera_masks_.resize(camera_data_ptrs_.size());
  for (std::size_t i = 0; i < camera_masks_.size(); ++i) {
    auto camera_mask_timestamp = rclcpp::Time(camera_data_ptrs_[i]->image_msg()->header.stamp);
    camera_masks_[i] =
      (lidar_stamp - camera_mask_timestamp.seconds()) < max_camera_lidar_delay_ ? 1.0 : 0.f;
  }
}

bool BEVFusionTRT::detect(
  const std::shared_ptr<const cuda_blackboard::CudaPointCloud2> & pc_msg_ptr,
  const std::vector<std::unique_ptr<CameraData>> & camera_data_ptrs,
  const std::vector<float> & camera_masks, const tf2_ros::Buffer & tf_buffer,
  std::vector<Box3D> & det_boxes3d, std::unordered_map<std::string, double> & proc_timing,
  bool & is_num_voxels_within_range)
{
  stop_watch_ptr_->toc("processing/inner", true);
  if (!preProcess(
        pc_msg_ptr, camera_data_ptrs, camera_masks, tf_buffer, is_num_voxels_within_range)) {
    RCLCPP_ERROR(rclcpp::get_logger("bevfusion"), "Pre-process failed. Skipping detection.");
    return false;
  }
  proc_timing.emplace(
    "debug/processing_time/preprocess_ms", stop_watch_ptr_->toc("processing/inner", true));

  if (!inference()) {
    RCLCPP_ERROR(rclcpp::get_logger("bevfusion"), "Inference failed. Skipping detection.");
    return false;
  }
  proc_timing.emplace(
    "debug/processing_time/inference_ms", stop_watch_ptr_->toc("processing/inner", true));

  if (!postProcess(det_boxes3d)) {
    RCLCPP_ERROR(rclcpp::get_logger("bevfusion"), "Post-process failed. Skipping detection");
    return false;
  }
  proc_timing.emplace(
    "debug/processing_time/postprocess_ms", stop_watch_ptr_->toc("processing/inner", true));

  return true;
}

bool BEVFusionTRT::preProcess(
  const std::shared_ptr<const cuda_blackboard::CudaPointCloud2> & pc_msg_ptr,
  const std::vector<std::unique_ptr<CameraData>> & camera_data_ptrs,
  const std::vector<float> & camera_masks, const tf2_ros::Buffer & tf_buffer,
  bool & is_num_voxels_within_range)
{
  is_num_voxels_within_range = true;

  if (!validatePointCloud(pc_msg_ptr)) {
    return false;
  }

  if (!vg_ptr_->enqueuePointCloud(pc_msg_ptr, tf_buffer)) {
    return false;
  }

  clearDeviceMemory();

  // Process images if sensor fusion is enabled
  if (config_.sensor_fusion_) {
    // Check if all image cameras are ready
    if (!checkImageCameraMatricesReady(camera_data_ptrs)) {
      rclcpp::Clock clock{RCL_ROS_TIME};
      RCLCPP_WARN_THROTTLE(
        rclcpp::get_logger("bevfusion"), clock, 1000,
        "Image and camera matrices are not ready. Skipping pre-processing.");
      return false;
    }

    // Process Images
    if (!processImages(camera_data_ptrs, camera_masks)) {
      RCLCPP_ERROR(
        rclcpp::get_logger("bevfusion"), "Failed to process images. Skipping detection.");
      return false;
    }
  }

  const auto num_points = vg_ptr_->generateSweepPoints(points_d_);
  if (num_points == 0) {
    RCLCPP_ERROR(
      rclcpp::get_logger("bevfusion"),
      "Empty sweep points (check the capacity of the buffer). Skipping detection.");
    return false;
  }

  CHECK_CUDA_ERROR(cudaStreamSynchronize(stream_));

  const std::int64_t num_voxels =
    processPointCloudVoxelization(num_points, is_num_voxels_within_range);
  if (num_voxels < 0) {
    return false;
  }

  configureTensorRTInputs(num_voxels, num_points);

  // Debug: Save ROI images after preprocessing
  if (config_.sensor_fusion_) {
    std::vector<uint8_t> roi_host_data(
      config_.roi_height_ * config_.roi_width_ * BEVFusionConfig::kNumRGBChannels);
    for (std::int64_t camera_id = 0; camera_id < config_.num_cameras_; camera_id++) {
      CHECK_CUDA_ERROR(cudaMemcpy(
        roi_host_data.data(),
        &roi_tensor_d_
          [camera_id * config_.roi_height_ * config_.roi_width_ * BEVFusionConfig::kNumRGBChannels],
        config_.roi_height_ * config_.roi_width_ * BEVFusionConfig::kNumRGBChannels,
        cudaMemcpyDeviceToHost));
    }
  }

  return true;
}

bool BEVFusionTRT::validatePointCloud(
  const std::shared_ptr<const cuda_blackboard::CudaPointCloud2> & pc_msg_ptr)
{
  if (!autoware::point_types::is_data_layout_compatible_with_point_xyzirc(pc_msg_ptr->fields)) {
    RCLCPP_ERROR(rclcpp::get_logger("bevfusion"), "Invalid point type. Skipping detection.");
    return false;
  }

  if (pc_msg_ptr->height * pc_msg_ptr->width == 0) {
    RCLCPP_ERROR(rclcpp::get_logger("bevfusion"), "Empty pointcloud. Skipping detection.");
    return false;
  }

  return true;
}

bool is_data_layout_compatible_with_point_xyzirc(
  const std::vector<sensor_msgs::msg::PointField> & fields)
{
  using PointIndex = autoware::point_types::PointXYZIRCIndex;
  using PointType = autoware::point_types::PointXYZIRC;
  if (fields.size() < 6) {
    return false;
  }
  bool same_layout = true;
  const auto & field_x = fields.at(static_cast<std::size_t>(PointIndex::X));
  same_layout &= field_x.name == "x";
  same_layout &= field_x.offset == offsetof(PointType, x);
  same_layout &= field_x.datatype == sensor_msgs::msg::PointField::FLOAT32;
  same_layout &= field_x.count == 1;
  const auto & field_y = fields.at(static_cast<std::size_t>(PointIndex::Y));
  same_layout &= field_y.name == "y";
  same_layout &= field_y.offset == offsetof(PointType, y);
  same_layout &= field_y.datatype == sensor_msgs::msg::PointField::FLOAT32;
  same_layout &= field_y.count == 1;
  const auto & field_z = fields.at(static_cast<std::size_t>(PointIndex::Z));
  same_layout &= field_z.name == "z";
  same_layout &= field_z.offset == offsetof(PointType, z);
  same_layout &= field_z.datatype == sensor_msgs::msg::PointField::FLOAT32;
  same_layout &= field_z.count == 1;
  const auto & field_intensity = fields.at(static_cast<std::size_t>(PointIndex::Intensity));
  same_layout &= field_intensity.name == "intensity";
  same_layout &= field_intensity.offset == offsetof(PointType, intensity);
  same_layout &= field_intensity.datatype == sensor_msgs::msg::PointField::UINT8;
  same_layout &= field_intensity.count == 1;
  const auto & field_return_type = fields.at(static_cast<std::size_t>(PointIndex::ReturnType));
  same_layout &= field_return_type.name == "return_type";
  same_layout &= field_return_type.offset == offsetof(PointType, return_type);
  same_layout &= field_return_type.datatype == sensor_msgs::msg::PointField::UINT8;
  same_layout &= field_return_type.count == 1;
  const auto & field_ring = fields.at(static_cast<std::size_t>(PointIndex::Channel));
  same_layout &= field_ring.name == "channel";
  same_layout &= field_ring.offset == offsetof(PointType, channel);
  same_layout &= field_ring.datatype == sensor_msgs::msg::PointField::UINT16;
  same_layout &= field_ring.count == 1;

  return same_layout;
}

bool VoxelGenerator::enqueuePointCloud(
  const std::shared_ptr<const cuda_blackboard::CudaPointCloud2> & msg_ptr,
  const tf2_ros::Buffer & tf_buffer)
{
  return pd_ptr_->enqueuePointCloud(msg_ptr, tf_buffer);
}

bool PointCloudDensification::enqueuePointCloud(
  const std::shared_ptr<const cuda_blackboard::CudaPointCloud2> & pointcloud_msg_ptr,
  const tf2_ros::Buffer & tf_buffer)
{
  const auto header = pointcloud_msg_ptr->header;

  if (param_.getPointcloudCacheSize() > 1) {
    auto transform_world2current =
      getTransform(tf_buffer, header.frame_id, param_.getWorldFrameId(), header.stamp);
    if (!transform_world2current) {
      return false;
    }
    auto affine_world2current = transformToEigen(transform_world2current.value());

    enqueue(pointcloud_msg_ptr, affine_world2current);
  } else {
    enqueue(pointcloud_msg_ptr, Eigen::Affine3f::Identity());
  }

  dequeue();

  return true;
}

std::optional<geometry_msgs::msg::Transform> getTransform(
  const tf2_ros::Buffer & tf_buffer, const std::string & target_frame_id,
  const std::string & source_frame_id, const rclcpp::Time & time)
{
  try {
    geometry_msgs::msg::TransformStamped transform_stamped;
    transform_stamped = tf_buffer.lookupTransform(
      target_frame_id, source_frame_id, time, rclcpp::Duration::from_seconds(0.5));
    return transform_stamped.transform;
  } catch (tf2::TransformException & ex) {
    RCLCPP_WARN_STREAM(rclcpp::get_logger("bevfusion"), ex.what());
    return std::nullopt;
  }
}

void PointCloudDensification::enqueue(
  const std::shared_ptr<const cuda_blackboard::CudaPointCloud2> & msg_ptr,
  const Eigen::Affine3f & affine_world2current)
{
  affine_world2current_ = affine_world2current;
  current_timestamp_ = rclcpp::Time(msg_ptr->header.stamp).seconds();

  PointCloudWithTransform pointcloud = {msg_ptr, affine_world2current.inverse()};

  pointcloud_cache_.push_front(std::move(pointcloud));
}

void PointCloudDensification::dequeue()
{
  if (pointcloud_cache_.size() > param_.getPointcloudCacheSize()) {
    pointcloud_cache_.pop_back();
  }
}

bool BEVFusionTRT::processImages(
  const std::vector<std::unique_ptr<CameraData>> & camera_data_ptrs,
  const std::vector<float> & camera_masks)
{
  for (std::int64_t camera_id = 0; camera_id < config_.num_cameras_; camera_id++) {
    // Check if the image encoding is supported
    if (!camera_data_ptrs[camera_id]->is_image_encoding_supported()) {
      rclcpp::Clock clock{RCL_ROS_TIME};
      RCLCPP_WARN_THROTTLE(
        rclcpp::get_logger("bevfusion"), clock, 1000,
        "Only RGB8 encoding is supported, and the image encoding is %s.",
        camera_data_ptrs[camera_id]->image_msg()->encoding.c_str());
      return false;
    }
    // Preprocess the image
    auto roi_tensor_offset = camera_data_ptrs[camera_id]->output_img_offset();
    if (!camera_data_ptrs[camera_id]->preprocess_image(&roi_tensor_d_[roi_tensor_offset])) {
      return false;
    }
  }

  CHECK_CUDA_ERROR(cudaMemcpyAsync(
    camera_masks_d_.get(), camera_masks.data(), config_.num_cameras_ * sizeof(float),
    cudaMemcpyHostToDevice, stream_));

  for (std::int64_t camera_id = 0; camera_id < config_.num_cameras_; camera_id++) {
    CHECK_CUDA_ERROR(camera_data_ptrs[camera_id]->sync_cuda_stream());
  }
  return true;
}

std::size_t CameraData::output_img_offset() const
{
  return output_img_offset_;
}

bool CameraData::preprocess_image(std::uint8_t * output_img)
{
  // 1. Copy image from CPU to GPU
  CHECK_CUDA_ERROR(cudaMemcpyAsync(
    image_buffer_d_.get(), image_msg_->data.data(),
    image_pre_processing_params_.original_image_height *
      image_pre_processing_params_.original_image_width * BEVFusionConfig::kNumRGBChannels,
    cudaMemcpyHostToDevice, stream_));

  if (image_pre_processing_params_.run_image_undistortion) {
    // 1. Check if original image shape is the same as the original image shape
    if (
      image_msg_->height != image_pre_processing_params_.original_image_height ||
      image_msg_->width != image_pre_processing_params_.original_image_width) {
      RCLCPP_ERROR(logger_, "Input image shape is not the same as the original image shape");
      return false;
    }

    // 2. Launch remap kernel for undistortion
    camera_preprocess_ptr_->remap_launch(
      image_buffer_d_.get(), undistorted_image_buffer_d_.get(),
      // Output dimensions (full resolution)
      image_pre_processing_params_.original_image_height,
      image_pre_processing_params_.original_image_width,
      // Input dimensions (full resolution)
      image_msg_->height, image_msg_->width,
      // Undistorted map x and y
      camera_matrices_ptr_->undistorted_map_x_d_.get(),
      camera_matrices_ptr_->undistorted_map_y_d_.get());

    // 3. Resize and extract ROI, and then saving to output_img
    // output_img is expected to be in the size of roi_height * roi_width * image channels (usually,
    camera_preprocess_ptr_->resizeAndExtractRoi_launch(
      undistorted_image_buffer_d_.get(), output_img,
      image_pre_processing_params_.original_image_height,
      image_pre_processing_params_.original_image_width,
      image_pre_processing_params_.resized_height, image_pre_processing_params_.resized_width,
      image_pre_processing_params_.roi_height, image_pre_processing_params_.roi_width,
      image_pre_processing_params_.roi_start_y, image_pre_processing_params_.roi_start_x);
  } else {
    // Skip the undistortion step and directly resize and extract ROI
    camera_preprocess_ptr_->resizeAndExtractRoi_launch(
      image_buffer_d_.get(), output_img, image_pre_processing_params_.original_image_height,
      image_pre_processing_params_.original_image_width,
      image_pre_processing_params_.resized_height, image_pre_processing_params_.resized_width,
      image_pre_processing_params_.roi_height, image_pre_processing_params_.roi_width,
      image_pre_processing_params_.roi_start_y, image_pre_processing_params_.roi_start_x);
  }

  return true;
}

cudaError_t CameraPreprocess::remap_launch(
  const std::uint8_t * input_img, std::uint8_t * output_img, int output_height,
  int output_width,                   // Output (destination) image dimensions
  int input_height, int input_width,  // Input (source) image dimensions
  const float * map_x, const float * map_y)
{
  // Define the block and grid dimensions based on output size
  dim3 threads(16, 16);
  dim3 blocks(divup(output_width, threads.x), divup(output_height, threads.y));

  // Launch the kernel
  remap_kernel<<<blocks, threads, 0, stream_>>>(
    input_img, output_img, output_height, output_width, input_height, input_width, map_x, map_y);

  // Check for errors
  return cudaGetLastError();
}

    unsigned int x, y, z;
#if defined(__cplusplus)
#if __cplusplus >= 201103L
    __host__ __device__ constexpr dim3(unsigned int vx = 1, unsigned int vy = 1, unsigned int vz = 1) : x(vx), y(vy), z(vz) {}

__global__ void remap_kernel(
  const std::uint8_t * __restrict__ input_img, std::uint8_t * __restrict__ output_img,
  int output_height, int output_width,  // Output (destination) image dimensions
  int input_height, int input_width,    // Input (source) image dimensions
  const float * __restrict__ map_x, const float * __restrict__ map_y)
{
  // Calculate the global thread indices for output image
  int x = blockIdx.x * blockDim.x + threadIdx.x;  // Width index in output
  int y = blockIdx.y * blockDim.y + threadIdx.y;  // Height index in output

  // Check if the thread corresponds to a valid pixel in output
  if (x >= output_width || y >= output_height) return;

  // Get the mapping coordinates for this output pixel.
  // Skip the first y rows with (y * output_width) and then skip the first x columns by adding x
  int map_idx = y * output_width + x;
  float src_x = map_x[map_idx];
  float src_y = map_y[map_idx];

  // Check if the mapped coordinates are valid in the input image
  // Skip the first y rows with (y * output_width) and then skip the first x columns by adding x.
  // Then skip the first 3 channels by multiplying by 3
  int out_idx = (y * output_width + x) * 3;
  if (src_x < 0 || src_y < 0 || src_x >= input_width || src_y >= input_height) {
    // Set to black for out-of-bounds pixels
    output_img[out_idx] = 0;
    output_img[out_idx + 1] = 0;
    output_img[out_idx + 2] = 0;
    return;
  }

  // Bilinear interpolation in unit square (0,0), (0,1), (1,0), (1,1)
  int x0 = static_cast<int>(floorf(src_x));
  int y0 = static_cast<int>(floorf(src_y));
  int x1 = x0 + 1;
  int y1 = y0 + 1;

  float dx = src_x - x0;
  float dy = src_y - y0;

  // Calculate interpolation weights
  float w00 = (1.0f - dx) * (1.0f - dy);
  float w01 = (1.0f - dx) * dy;
  float w10 = dx * (1.0f - dy);
  float w11 = dx * dy;

// Process each color channel
#pragma unroll
  for (int c = 0; c < 3; ++c) {
    float v00 = 0.0f, v01 = 0.0f, v10 = 0.0f, v11 = 0.0f;

    // Get pixel values with boundary checks
    if (x0 >= 0 && x0 < input_width && y0 >= 0 && y0 < input_height)
      v00 = static_cast<float>(input_img[(y0 * input_width + x0) * 3 + c]);
    if (x0 >= 0 && x0 < input_width && y1 >= 0 && y1 < input_height)
      v01 = static_cast<float>(input_img[(y1 * input_width + x0) * 3 + c]);
    if (x1 >= 0 && x1 < input_width && y0 >= 0 && y0 < input_height)
      v10 = static_cast<float>(input_img[(y0 * input_width + x1) * 3 + c]);
    if (x1 >= 0 && x1 < input_width && y1 >= 0 && y1 < input_height)
      v11 = static_cast<float>(input_img[(y1 * input_width + x1) * 3 + c]);

    // Interpolate and store the result
    float interpolated_value = w00 * v00 + w01 * v01 + w10 * v10 + w11 * v11;
    // Clamp the interpolated value to [0, 255] range
    interpolated_value = fmaxf(0.0f, fminf(255.0f, interpolated_value));
    output_img[out_idx + c] = static_cast<std::uint8_t>(interpolated_value);
  }
}

cudaError_t CameraPreprocess::resizeAndExtractRoi_launch(
  const std::uint8_t * input_img, std::uint8_t * output_img, int H,
  int W,                    // Original image dimensions
  int H2, int W2,           // Resized image dimensions
  int H3, int W3,           // ROI dimensions
  int y_start, int x_start  // ROI top-left coordinates in resized image
)
{
  // Define the block and grid dimensions
  dim3 threads(16, 16);
  dim3 blocks(divup(W3, threads.x), divup(H3, threads.y));

  // Launch the kernel
  resizeAndExtractRoi_kernel<<<blocks, threads, 0, stream_>>>(
    input_img, output_img, H, W, H2, W2, H3, W3, y_start, x_start);

  // Check for errors
  return cudaGetLastError();
}

__global__ void resizeAndExtractRoi_kernel(
  const std::uint8_t * __restrict__ input_img, std::uint8_t * __restrict__ output_img, int in_h,
  int in_w,                         // Input dimensions
  int resize_h, int resize_w,       // Target resize dimensions (before cropping)
  int roi_h, int roi_w,             // Output ROI dimensions
  int roi_y_start, int roi_x_start  // Top-left of ROI in the resized coordinate space
)
{
  // 1. Calculate thread target pixel in the ROI (Output Image)
  int out_x = blockIdx.x * blockDim.x + threadIdx.x;
  int out_y = blockIdx.y * blockDim.y + threadIdx.y;

  if (out_x >= roi_w || out_y >= roi_h) return;

  // 2. Map ROI pixel to the virtual Resized Image coordinates
  //    (The image that *would* exist if we resized the whole thing)
  float resized_x = static_cast<float>(out_x + roi_x_start);
  float resized_y = static_cast<float>(out_y + roi_y_start);

  // 3. Calculate Scale Factors (Input / Resized)
  //    scale > 1.0 means downsampling
  float scale_x = static_cast<float>(in_w) / static_cast<float>(resize_w);
  float scale_y = static_cast<float>(in_h) / static_cast<float>(resize_h);

  // 4. Map to Input Image Center Point
  //    Standard alignment: (x + 0.5) * scale - 0.5
  float center_x = (resized_x + 0.5f) * scale_x - 0.5f;
  float center_y = (resized_y + 0.5f) * scale_y - 0.5f;

  // 5. Determine Support Size (Kernel Radius)
  //    For downsampling, support scales with the downsampling factor (Anti-aliasing).
  //    For upsampling (scale < 1), support is 1.0 (Standard Bilinear).
  float support_x = (scale_x > 1.0f) ? scale_x : 1.0f;
  float support_y = (scale_y > 1.0f) ? scale_y : 1.0f;

  // 6. Define Sampling Bounds in Input
  //    We loop over pixels within [center - support, center + support]
  int x_min = static_cast<int>(ceilf(center_x - support_x));
  int x_max = static_cast<int>(floorf(center_x + support_x));
  int y_min = static_cast<int>(ceilf(center_y - support_y));
  int y_max = static_cast<int>(floorf(center_y + support_y));

  // Clamp to input image boundaries
  x_min = max(0, x_min);
  x_max = min(in_w - 1, x_max);
  y_min = max(0, y_min);
  y_max = min(in_h - 1, y_max);

  // Accumulators
  //    float sum_r = 0.0f;
  //    float sum_g = 0.0f;
  //    float sum_b = 0.0f;
  float sum_first_channel = 0.0f;
  float sum_second_channel = 0.0f;
  float sum_third_channel = 0.0f;
  float sum_weight = 0.0f;

  // 7. Convolution Loop (Triangle/Bilinear Filter)
  // TODO(KokSeang): If necessary, optimize with im2col, separate horizontal and vertical
  // filtering, etc.
  for (int y = y_min; y <= y_max; ++y) {
    // Y-weight: Triangle filter (1 - distance / support)
    float dy = (center_y - y);
    float wy = max(0.0f, 1.0f - abs(dy) / support_y);

    // Optimization: Pre-calculate Y-offset index
    int row_offset = y * in_w;

    for (int x = x_min; x <= x_max; ++x) {
      // X-weight
      float dx = (center_x - x);
      float wx = max(0.0f, 1.0f - abs(dx) / support_x);

      // Combined weight
      float w = wx * wy;

      // Skip negligible weights
      if (w > 0.0f) {
        // To save the image in CHW format, the index is calculated as (row_offset + x) * 3.
        int idx = (row_offset + x) * 3;
        sum_first_channel += input_img[idx] * w;
        sum_second_channel += input_img[idx + 1] * w;
        sum_third_channel += input_img[idx + 2] * w;
        sum_weight += w;
      }
    }
  }

  // 8. Normalize Weights and Write Output
  //    Avoid division by zero if weight sum is tiny (shouldn't happen inside valid ROI)
  if (sum_weight > 0.0f) {
    sum_first_channel /= sum_weight;
    sum_second_channel /= sum_weight;
    sum_third_channel /= sum_weight;
  }

  // 9. Normalize (Mean/Std) and Write to Output (Planar CHW)
  //    Output layout: [Batch/Camera, Channel, Height, Width]
  int area = roi_h * roi_w;
  int out_idx = out_y * roi_w + out_x;

  // Channel 0
  output_img[(0 * area + out_idx)] = sum_first_channel;
  // Channel 1
  output_img[(1 * area + out_idx)] = sum_second_channel;
  // Channel 2
  output_img[(2 * area + out_idx)] = sum_third_channel;
}

  bool run_image_undistortion;
  std::int64_t crop_height;
  std::int64_t crop_width;
  std::int64_t resized_height;
  std::int64_t resized_width;
  std::int64_t roi_start_y;
  std::int64_t roi_start_x;

  ImagePreProcessingParams(
    const std::int64_t original_image_height, const std::int64_t original_image_width,
    const std::int64_t roi_height, const std::int64_t roi_width, const float image_aug_scale_y,
    const float image_aug_scale_x, const bool run_image_undistortion);
};

